%[text] # Plot
%[text] UWCC Structural Analysis: Heerod Sahraei
%[text] Run after Main.m. For the plotting of various important graphs.
%[text] ## Moment and Shear
%[text] ### Inputs
toPlot = ["RaceStands", "MaleTandem","FemaleTandem",];
displayName = ["Race Stands", "MaleTandem","FemaleTandem"];
colors = ["red","blue","green"];
%[text] ### Diagrams
close;
hold on; %[output:112a3c60]
for i = 1:numel(toPlot) %[output:group:0a87e3a1]
    V = LoadCases.(toPlot(i)).ShearDistribution;
    
    plot(xInterp,V,'Color',colors(i),'LineWidth',2,'DisplayName',displayName(i)); %[output:112a3c60]
    xlim([xInterp(1) xInterp(end)]);
    title('Shear Diagram');
    xlabel('Longitudinal Station (in.)');
    ylabel('Shear (lbs.)');
    legend("Location","southeast");
end %[output:group:0a87e3a1]
figure; %[output:666362ad]
hold on; %[output:666362ad]
for i = 1:numel(toPlot) %[output:group:92b2714e]
    M = LoadCases.(toPlot(i)).MomentDistribution;
    
    plot(xInterp,M,'Color', colors(i), 'LineWidth', 2, 'DisplayName',displayName(i)); %[output:666362ad]
    xlim([xInterp(1) xInterp(end)]);
    title('Moment Diagram');
    xlabel('Longitudinal Station (in.)');
    ylabel('Bending Moment (lbs.*in.)');
    legend("Location","southeast");
    
end %[output:group:92b2714e]
%%
%[text] ## FBD
caseName = caseNames(5); %[control:dropdown:6f82]{"position":[12,24]}

P = LoadCases.(caseName{:}).PointLoads;
buoyancy = LoadCases.(caseName{:}).BuoyantDistribution;

figure('Color','w'); hold on; grid on; %[output:693bc748]
plot(xInterp, buoyancy, 'b-', 'LineWidth',1.6); %[output:693bc748]
plot(xInterp, selfWeightInterp, 'r--', 'LineWidth',1.6); %[output:693bc748]
yline(0,'k-'); %[output:693bc748]

for i = 1:(numel(P)/2)
    x0 = P(1,i);
    Pmag = P(2,i);
    quiver(x0, 0, 0, Pmag/200, 0, 'MaxHeadSize',1, 'Color','k', 'LineWidth',1.5); % represent paddlers as arrows %[output:693bc748]
end

xlabel('x (in)'); %[output:693bc748]
ylabel('Load (lbf/in)'); %[output:693bc748]
title('Buoyant Load, Self Weight, and Point Loadings'); %[output:693bc748]
legend('Buoyancy (up)','Self Weight (down)','Point Loads','Location','best'); %[output:693bc748]

